INSERT INTO `destinacije` VALUES (1,'les-orres','Les Orres','Skrivena perla Francuskih Alpa — staze pod stalnim suncem, kompaktno selo i savršena dnevna preglednost. Idealno za porodice i one koji traže privatnost daleko od gužve.','Francuska','Francuske Alpe',44.455300,6.537200,1580,110.00,1),(2,'chamonix','Chamonix-Mont-Blanc','Legendarno utočište alpinista. U podnožju najvišeg evropskog vrha, sa 4 odvojena ski područja i autentičnom francuskom čaršijom. Mecca za napredne skijaše.','Francuska','Francuske Alpe',45.923700,6.869400,1530,115.00,1),(3,'val-thorens','Val Thorens','Najviše skijalište Evrope na 2300m — Les 3 Vallées, 600 km povezanih staza, garantovani sneg do maja. Pravi raj za pisteur-e koji ne posustaju.','Francuska','Francuske Alpe',45.298000,6.580000,1620,120.00,1),(6,'st-anton','St. Anton am Arlberg','Kolevka alpskog skijanja — gde je rođen moderni skijaški sport 1901. Apres-ski legenda, Schindlerov Kar, 305 km povezanih staza Arlberg sistema.','Austrija','Tirol',46.749700,10.270200,1025,65.00,1),(7,'kopaonik','Kopaonik','Krov Srbije — najveći domaći ski centar, 60 km staza, 25 žičara. Komforna alternativa Alpima bez graničnih prelaza, sa srpskom hranom i razumnim cenama.','Srbija','Centralna Srbija',43.286000,20.816400,280,0.00,7),(8,'bansko','Bansko','Najpristupačnije pravo skijalište regiona — 75 km staza, gondola direktno iz centra grada, balkanska gostoljubivost i cene 30% niže od Alpa.','Bugarska','Pirin',41.837800,23.488400,530,18.00,5);
