INSERT INTO `recenzije` VALUES (1,NULL,'Marija T.','MT','Les Orres, Francuska','Neverovatno iskustvo! Staze su savršeno pripremljene, sneg prašinast celu nedelju. Organizacija Snowbase bila je besprekorna od prvog do poslednjeg dana.',5,'Januar 2026.',NULL,1,10),(2,NULL,'Stefan K.','SK','St. Anton, Austrija','Treće godišnje putovanje. Smeštaj tačno prema opisu, transfer brz, granični prelaz bez čekanja. Jednom kad probate Snowbase, ne idete drugde.',5,'Februar 2026.',NULL,1,20),(3,NULL,'Milan & Tara','MT','Val Thorens, Francuska','Najveće skijalište koje smo iskusili — staze beskrajne, sneg garantovan. Snowbase organizacija prvoklasna od polaska do povratka.',5,'Decembar 2025.',NULL,1,30),(4,NULL,'Nikola P.','NP','Chamonix, Francuska','Sve savršeno isplanirano — od polaska iz Beograda do povratka, nula stresa. Kalkulator je bio tačan do poslednjeg evra.',5,'Januar 2026.',NULL,1,40),(5,1,'Marko D.',NULL,NULL,'Savršeno organizovan put. Staze prelepe, hotel taman koliko nam treba. Ekipa Snowbase brza i profesionalna.',5,'Januar 2026.','[\"Staze ★★★★★\", \"Organizacija ★★★★★\"]',0,10),(6,2,'Marko D.',NULL,NULL,'Savršeno organizovan put. Staze prelepe, hotel taman koliko nam treba. Ekipa Snowbase brza i profesionalna.',5,'Januar 2026.','[\"Staze ★★★★★\", \"Organizacija ★★★★★\"]',0,10),(7,3,'Marko D.',NULL,NULL,'Savršeno organizovan put. Staze prelepe, hotel taman koliko nam treba. Ekipa Snowbase brza i profesionalna.',5,'Januar 2026.','[\"Staze ★★★★★\", \"Organizacija ★★★★★\"]',0,10),(8,6,'Marko D.',NULL,NULL,'Savršeno organizovan put. Staze prelepe, hotel taman koliko nam treba. Ekipa Snowbase brza i profesionalna.',5,'Januar 2026.','[\"Staze ★★★★★\", \"Organizacija ★★★★★\"]',0,10),(9,8,'Marko D.',NULL,NULL,'Savršeno organizovan put. Staze prelepe, hotel taman koliko nam treba. Ekipa Snowbase brza i profesionalna.',5,'Januar 2026.','[\"Staze ★★★★★\", \"Organizacija ★★★★★\"]',0,10),(10,7,'Marko D.',NULL,NULL,'Savršeno organizovan put. Staze prelepe, hotel taman koliko nam treba. Ekipa Snowbase brza i profesionalna.',5,'Januar 2026.','[\"Staze ★★★★★\", \"Organizacija ★★★★★\"]',0,10),(12,1,'Jelena & Vuk',NULL,NULL,'Treća sezona zaredom. Cena je fer, kvalitet izuzetan. Ski škola savršena za našu decu — preporučujemo svima.',5,'Februar 2026.','[\"Porodično ★★★★★\", \"Smeštaj ★★★★☆\"]',0,20),(13,2,'Jelena & Vuk',NULL,NULL,'Treća sezona zaredom. Cena je fer, kvalitet izuzetan. Ski škola savršena za našu decu — preporučujemo svima.',5,'Februar 2026.','[\"Porodično ★★★★★\", \"Smeštaj ★★★★☆\"]',0,20),(14,3,'Jelena & Vuk',NULL,NULL,'Treća sezona zaredom. Cena je fer, kvalitet izuzetan. Ski škola savršena za našu decu — preporučujemo svima.',5,'Februar 2026.','[\"Porodično ★★★★★\", \"Smeštaj ★★★★☆\"]',0,20),(15,6,'Jelena & Vuk',NULL,NULL,'Treća sezona zaredom. Cena je fer, kvalitet izuzetan. Ski škola savršena za našu decu — preporučujemo svima.',5,'Februar 2026.','[\"Porodično ★★★★★\", \"Smeštaj ★★★★☆\"]',0,20),(16,8,'Jelena & Vuk',NULL,NULL,'Treća sezona zaredom. Cena je fer, kvalitet izuzetan. Ski škola savršena za našu decu — preporučujemo svima.',5,'Februar 2026.','[\"Porodično ★★★★★\", \"Smeštaj ★★★★☆\"]',0,20),(17,7,'Jelena & Vuk',NULL,NULL,'Treća sezona zaredom. Cena je fer, kvalitet izuzetan. Ski škola savršena za našu decu — preporučujemo svima.',5,'Februar 2026.','[\"Porodično ★★★★★\", \"Smeštaj ★★★★☆\"]',0,20);
